  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart(e.targetTouches[0].clientX);
    touchStartY.current = e.targetTouches[0].clientY;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (touchStart === null) return;

    // 1. GLOBAL BLOCKERS (Immersive Mode or Settings Open)
    if (activeImmersiveArticle || isSettingsOpen) {
        setTouchStart(null);
        return;
    }

    const touchEnd = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const distance = touchStart - touchEnd;
    const deltaY = Math.abs(touchEndY - touchStartY.current);
    const screenWidth = window.innerWidth;
    const screenHeight = window.innerHeight;

    // Edge Detection for settings (Global Gesture)
    const isEdgeSwipe = touchStart > screenWidth * 0.85;

    if (isEdgeSwipe && distance > 50 && distance > deltaY) {
      setIsSettingsOpen(true);
      if (navigator.vibrate) navigator.vibrate(15);
      setTouchStart(null);
      return;
    }

    // 2. TOPIC NAVIGATION SWIPE (Restricted Zone)
    if (!isEdgeSwipe && activeTab === 'discover') {
        const startY = touchStartY.current;

        // SAFE ZONE: Between Topic Bar (approx > 120px) and Bottom Dock (approx < screenHeight - 100px)
        const isSafeZone = startY > 120 && startY < (screenHeight - 100);

        if (isSafeZone && Math.abs(distance) > 60 && Math.abs(distance) > deltaY) {
            if (distance > 0) handleNextTopic();
            else handlePrevTopic();
        }
    }
    setTouchStart(null);
