const extractStats = (text: string) => {
  const nMatch = text.match(/\bn\s*[=:]\s*(\d+(?:,\d+)*)/i);
  const pMatch = text.match(/p\s*[<>=]\s*[\d\.]+/i);
  const hrMatch = text.match(/\b(HR|Hazard Ratio)\s*[:=]?\s*(\d+\.\d+)/i);
  const rrMatch = text.match(/\b(RR|Relative Risk)\s*[:=]?\s*(\d+\.\d+)/i);
  const orMatch = text.match(/\b(OR|Odds Ratio)\s*[:=]?\s*(\d+\.\d+)/i);

  return {
    n: nMatch ? nMatch[1] : null,
    p: pMatch ? pMatch[0] : null,
    hr: hrMatch ? `HR ${hrMatch[2]}` : null,
    rr: rrMatch ? `RR ${rrMatch[2]}` : null,
    or: orMatch ? `OR ${orMatch[2]}` : null
  };
};

const extractConclusion = (text: string): string => {
    // 1. Try explicit section
    const match = text.match(/(?:Conclusion|Conclusión|Conclusions|Conclusiones)[:\.]\s*(.*)/i);
    if (match) return match[1].split('.')[0] + '.';

    // 2. Fallback to last sentence
    const sentences = text.split(/[.!?]\s+/).filter(s => s.length > 20);
    return sentences.length > 0 ? sentences[sentences.length - 1] + '.' : text.substring(0, 150) + '...';
};

